class SessionManager {

    public AuthenticatedSession createSession(SamlResponse samlResponse) throws SamlProcessingException {
        Objects.requireNonNull(samlResponse, "samlResponse");

        SamlAssertion primaryAssertion = samlResponse.getAssertions().get(0);
        String principal = primaryAssertion.getNameId();

        if (principal == null || principal.trim().isEmpty()) {
            throw new SamlProcessingException("Cannot create authenticated session: assertion subject NameID is missing");
        }

        Map<String, List<String>> mergedAttributes = new HashMap<>();
        for (SamlAssertion assertion : samlResponse.getAssertions()) {
            for (Map.Entry<String, List<String>> entry : assertion.getAttributes().entrySet()) {
                mergedAttributes.computeIfAbsent(entry.getKey(), k -> new ArrayList<>()).addAll(entry.getValue());
            }
        }

        return new AuthenticatedSession(
                UUID.randomUUID().toString(),
                principal,
                Instant.now(),
                samlResponse.getAssertions(),
                mergedAttributes
        );
    }
}

