class SamlNamespaceContext implements NamespaceContext {

    @Override
    public String getNamespaceURI(String prefix) {
        if ("samlp".equals(prefix)) {
            return "urn:oasis:names:tc:SAML:2.0:protocol";
        }
        if ("saml".equals(prefix)) {
            return "urn:oasis:names:tc:SAML:2.0:assertion";
        }
        if ("xml".equals(prefix)) {
            return XMLConstants.XML_NS_URI;
        }
        return XMLConstants.NULL_NS_URI;
    }

    @Override
    public String getPrefix(String namespaceURI) {
        if ("urn:oasis:names:tc:SAML:2.0:protocol".equals(namespaceURI)) {
            return "samlp";
        }
        if ("urn:oasis:names:tc:SAML:2.0:assertion".equals(namespaceURI)) {
            return "saml";
        }
        return null;
    }

    @Override
    public Iterator<String> getPrefixes(String namespaceURI) {
        String prefix = getPrefix(namespaceURI);
        if (prefix == null) {
            return Collections.emptyIterator();
        }
        return Collections.singleton(prefix).iterator();
    }
}

